@dataclass
class MarkerCounters:
    slot_0: int = 0x00
    slot_1: int = 0x00
    slot_2: int = 0x00
    slot_3: int = 0x00
    slot_4: int = 0x00

    def clear(self) -> None:
        self.slot_0 = 0x00
        self.slot_1 = 0x00
        self.slot_2 = 0x00
        self.slot_3 = 0x00
        self.slot_4 = 0x00

    def get(self, slot: int) -> int:
        idx = int(slot)
        if idx == 0:
            return self.slot_0 & 0xFF
        if idx == 1:
            return self.slot_1 & 0xFF
        if idx == 2:
            return self.slot_2 & 0xFF
        if idx == 3:
            return self.slot_3 & 0xFF
        if idx == 4:
            return self.slot_4 & 0xFF
        raise ValueError(f"Marker slot out of range: {idx}")

    def set(self, slot: int, value: int) -> None:
        idx = int(slot)
        v = int(value) & 0xFF
        if idx == 0:
            self.slot_0 = v
            return
        if idx == 1:
            self.slot_1 = v
            return
        if idx == 2:
            self.slot_2 = v
            return
        if idx == 3:
            self.slot_3 = v
            return
        if idx == 4:
            self.slot_4 = v
            return
        raise ValueError(f"Marker slot out of range: {idx}")

    def values(self) -> tuple[int, int, int, int, int]:
        return (
            self.slot_0 & 0xFF,
            self.slot_1 & 0xFF,
            self.slot_2 & 0xFF,
            self.slot_3 & 0xFF,
            self.slot_4 & 0xFF,
        )

    def is_clear(self, slot: int) -> bool:
        return self.get(slot) == 0x00

    def active_count(self) -> int:
        return sum(value for value in self.values()) & 0xFF

    def any_active(self) -> bool:
        return self.active_count() != 0x00

    def all_active(self) -> bool:
        return self.active_count() == 0x05


_DEFAULT_DEFINE_KEYS_SLOTS: Final[tuple[tuple[int, int], ...]] = (
    # Default modern keyboard profile:
    # slot1=Up(W), slot2=Down(S), slot3=Left(A), slot4=Right(D),
    # slot5=Action(Space), slot6=Secondary/overlay(E).
    (0xFBFE, 0x4F),  # W
    (0xFDFE, 0x4F),  # S
    (0xFDFE, 0x47),  # A
    (0xFDFE, 0x57),  # D
    (0x7FFE, 0x47),  # Space
    (0xFBFE, 0x57),  # E
)
_DEFAULT_HIGHSCORE_EDIT_ROW_INDEX: Final[int] = 0x00
_DEFAULT_HIGHSCORE_NAME_EDIT_STATE: Final[int] = 0x00
