class AlienEvolutionData:
    """
    Alien Evolution data blocks initialized from embedded ROM bytes.

    All blocks and internal pointer labels are wired statically via explicit
    assignments in __init__.
    """

    def __init__(self) -> None:
        # ZX 0x4000..0x57FF
        self.var_display_bitmap_ram = bytearray(0x1800)
        # ZX 0x5800..0x5AFF
        self.var_display_attribute_ram = bytearray(0x0300)
        # ZX 0x5B00..0x5DBF
        self.var_zx_system_workspace_ram = bytearray.fromhex("")
        # ZX 0x5DC0..0x65BF
