        self.const_title_attr_source = bytes.fromhex("")
        # ZX 0x66C0..0x69E5
        self.const_text_glyph_source_head = bytes.fromhex("")
        # ZX 0x69E6..0x6AA5
        # Six control icons, 32 bytes each (two 16-row strips).
        self.const_control_icon_set_table: tuple[int, ...] = tuple(bytes.fromhex(""))
        # ZX 0x6AA6..0x6AB5
        self.const_unresolved_pattern_candidate_16b = bytes.fromhex("000000006b6b6b6b6868687b00000000")
        # ZX 0x6AB6..0x6ABC
        self.const_unresolved_pre_highscore_tail = bytes.fromhex("00000000de1818")
        # ZX 0x6ABD..0x6AD5
        self.str_highscore_row_template_1 = bytearray.fromhex("110d2d2132232f0006003429342f0e0e0e0d101010101010ff")
        # ZX 0x6AD6..0x6AEE
        self.str_highscore_row_template_2 = bytearray.fromhex("120d212c29252e0025362f2c3534292f2e0d101010101010ff")
        # ZX 0x6AEF..0x6B07
        self.str_highscore_row_template_3 = bytearray.fromhex("130d2732252d2c292e0e0e0e0e0e0e0e0e0d101010101010ff")
        # ZX 0x6B08..0x6B20
        self.str_highscore_row_template_4 = bytearray.fromhex("140d212c27213236250e0e0e0e0e0e0e0e0d101010101010ff")
        # ZX 0x6B21..0x6B39
        self.str_highscore_row_template_5 = bytearray.fromhex("150d34282500252e240e0e0e0e0e0e0e0e0d101010101010ff")
        # ZX 0x6ABD..0x6B39
        # Semantic runtime grouping of the five mutable high-score rows.
        self.var_highscore_row_templates: tuple[bytearray, ...] = (
            self.str_highscore_row_template_1,
            self.str_highscore_row_template_2,
            self.str_highscore_row_template_3,
            self.str_highscore_row_template_4,
            self.str_highscore_row_template_5,
        )
        # ZX 0x6C19..0x6C24
        self.str_frontend_option_stream_1 = bytes.fromhex("11600d2b2539222f213224ff")
        # ZX 0x6C25..0x6C34
        self.str_frontend_option_stream_2 = bytes.fromhex("12600d292e34253226212325002929ff")
        # ZX 0x6C35..0x6C40
        self.str_frontend_option_stream_3 = bytes.fromhex("13600d2b252d3033342f2eff")
        # ZX 0x6C41..0x6C4A
        self.str_frontend_option_stream_4 = bytes.fromhex("14600d233532332f32ff")
        # ZX 0x6C4B..0x6C59
        self.str_frontend_option_stream_5 = bytes.fromhex("15600d242526292e25002b253933ff")
        # ZX 0x6C5A..0x6C62
        self.str_frontend_option_stream_6 = bytes.fromhex("16600d3334213234ff")
        # ZX 0x6C63..0x6C81
        self.str_byline_stream = bytes.fromhex("2239002d2132232f00232132322133232f00212e2400323529003429342fff")

        # ZX 0x6CFE..0x6D0F
        # Original layout was sparse bytes; runtime stores semantic slots directly.
        self.const_define_keys_descriptor_table: list[DefineKeySlot] = [
            DefineKeySlot(
                port_word=port_word,
                mask_byte=mask_byte,
            )
            for port_word, mask_byte in _DEFAULT_DEFINE_KEYS_SLOTS
        ]
        # ZX 0x6FAD..0x6FB9
        self.str_highscore_header_stream = bytes.fromhex("28212c2c002f260026212d25ff")
        # ZX 0x6FBA..0x6FBB
        self.const_highscore_header_tail_word = bytes.fromhex("816c")

        # ZX 0x7110..0x7111
        # Original layout was a little-endian pointer to active high-score row template.
        # Runtime stores semantic row index [0..4].
        self.var_highscore_edit_row_index: int = _DEFAULT_HIGHSCORE_EDIT_ROW_INDEX

        # ZX 0x7112..0x7112
        self.var_highscore_name_edit_state: int = _DEFAULT_HIGHSCORE_NAME_EDIT_STATE
        # ZX 0x7113..0x7122
        self.str_name_entry_prompt_stream = bytes.fromhex("252e34253200392f3532002e212d25ff")
        # ZX 0x7154..0x7154
        self.const_panel_source_padding_byte = bytes(0x0001)
        # ZX 0x7155..0x7954
        self.const_mission_panel_bitmap_source = bytes.fromhex("")
        # ZX 0x7955..0x7A54
        self.const_mission_panel_attr_source = bytes.fromhex("")
        # ZX 0x7A55..0x7D94
        self.const_mission_panel_tile_strip = bytes.fromhex("")
        # ZX 0x7D95..0x7E14
        self.const_mission_frame_pattern_source = bytes.fromhex("0000000001071f7f0000000080e0f8fe7ffff9e698608000feff9f6719060100000000000304090a00000000c0201010101020c000000000080804030000000000000000061e78000000000060781e001e7a665860000000785e661a06000000000000000001020500000000008040a0a0408000000000000502010000000000")
        # ZX 0x7E15..0x7E55
        self.const_scenario_preset_a_stream_1 = bytes.fromhex("16b4ecb4b4ecb4b4b4ececf3b4b4b4b4ecececf3f3eeb4eeeef3ecf3ecf3eeeeb4ecf3ecf3eeeef3b4ecf3b4ecf3b4ecf3eeeef3ecf3f7f3f7f3faf3faeefcee40")
        # ZX 0x7E56..0x7E96
        self.const_scenario_preset_a_stream_2 = bytes.fromhex("1629012929012929290101ff29292929010101ffffff29ffffff01ff01ffffff2901ff01ffffffff2901ff2901ff2901ffffffff01ff29ff29ff29ff29ff29ff40")
        # ZX 0x7E97..0x7FFF
        self.const_preset_a_padding_tail = bytes(0x0169)
        # ZX 0x8000..0x89C3
        self.var_level_map_mode_0 = bytearray.fromhex("")

        # ZX 0x89C4..0x89C5
        # Raw prelude bytes are kept for contiguous map/staging edge semantics.
        renderer_workspace_visible_cell_staging_prelude = bytearray(0x0002)
        # Typed u16 prelude word used by staging setup patches.
        self.var_visible_cell_staging_prelude: int = (
            renderer_workspace_visible_cell_staging_prelude[0]
            | (renderer_workspace_visible_cell_staging_prelude[1] << 8)
        ) & 0xFFFF
        # ZX 0x89C6..0x8C0F
        renderer_workspace_visible_cell_staging_lattice = bytearray(0x024A)
        # ZX 0x8C10..0x8C25
        renderer_workspace_visible_cell_staging_mid_window = bytearray(0x0016)
        # ZX 0x8C26..0x8D5F
        renderer_workspace_visible_cell_staging_tail_window = bytearray.fromhex("")
        # ZX 0x8D60..0x8F7F
        renderer_workspace_render_work_area_tail = bytearray.fromhex("")
        # ZX 0x8F80..0x90FF
        renderer_workspace_cell_blit_work_buffer = bytearray.fromhex("")
        # ZX 0x9100..0xA38D
        renderer_workspace_linear_viewport_work_buffer = bytearray.fromhex("")

        # ZX 0x89C4..0xA38D
        # Unified renderer workspace with semantically-addressed subregions.
        self.var_renderer_workspace = bytearray(RENDERER_WORKSPACE_LEN_TOTAL)
        renderer_workspace = self.var_renderer_workspace
        renderer_workspace[
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_PRELUDE:
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_PRELUDE + RENDERER_WORKSPACE_LEN_VISIBLE_CELL_STAGING_PRELUDE
        ] = renderer_workspace_visible_cell_staging_prelude
        renderer_workspace[
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_LATTICE:
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_LATTICE + RENDERER_WORKSPACE_LEN_VISIBLE_CELL_STAGING_LATTICE
        ] = renderer_workspace_visible_cell_staging_lattice
        renderer_workspace[
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_MID_WINDOW:
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_MID_WINDOW + RENDERER_WORKSPACE_LEN_VISIBLE_CELL_STAGING_MID_WINDOW
        ] = renderer_workspace_visible_cell_staging_mid_window
        renderer_workspace[
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_TAIL_WINDOW:
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_TAIL_WINDOW + RENDERER_WORKSPACE_LEN_VISIBLE_CELL_STAGING_TAIL_WINDOW
        ] = renderer_workspace_visible_cell_staging_tail_window
        renderer_workspace[
            RENDERER_WORKSPACE_OFF_RENDER_WORK_AREA_TAIL:
            RENDERER_WORKSPACE_OFF_RENDER_WORK_AREA_TAIL + RENDERER_WORKSPACE_LEN_RENDER_WORK_AREA_TAIL
        ] = renderer_workspace_render_work_area_tail
        renderer_workspace[
            RENDERER_WORKSPACE_OFF_CELL_BLIT_WORK_BUFFER:
            RENDERER_WORKSPACE_OFF_CELL_BLIT_WORK_BUFFER + RENDERER_WORKSPACE_LEN_CELL_BLIT_WORK_BUFFER
        ] = renderer_workspace_cell_blit_work_buffer
        renderer_workspace[
            RENDERER_WORKSPACE_OFF_LINEAR_VIEWPORT_WORK_BUFFER:
            RENDERER_WORKSPACE_OFF_LINEAR_VIEWPORT_WORK_BUFFER + RENDERER_WORKSPACE_LEN_LINEAR_VIEWPORT_WORK_BUFFER
        ] = renderer_workspace_linear_viewport_work_buffer

        # ZX 0xA669..0xA66A
        # Typed u16 scratch for saved stack pointer during linear fill.
        self.var_render_stack_saved_sp: int = 0x0000

        # ZX 0xA66B..0xA66C
        # Original layout was little-endian cursor pointer into staging lattice.
        self.var_renderer_staging_cursor_ptr: BlockPtr = BlockPtr(
            self.var_renderer_workspace,
            RENDERER_WORKSPACE_OFF_VISIBLE_CELL_STAGING_LATTICE,
        )
        # ZX 0xA66D..0xA66E
        # +0x00 inner loop counter, +0x01 outer zig-zag pass counter.
        self.var_renderer_fill_counters: RendererFillCounters = RendererFillCounters(
            counter_0=_DEFAULT_RENDERER_FILL_COUNTERS.counter_0,
            counter_1=_DEFAULT_RENDERER_FILL_COUNTERS.counter_1,
        )
        # ZX 0xA859..0xA888
        # Runtime consumes these as 8 little-endian overlapping u16 words.
        self.const_floor_pattern_mode_1_words: tuple[int, ...] = (0x8181, 0x0481, 0x0204, 0x0802, 0x1808, 0x6618, 0x4666, 0x8146)
        self.const_floor_pattern_mode_0_words: tuple[int, ...] = (0xAAAA, 0x55AA, 0x5555, 0xAA55, 0xAAAA, 0x55AA, 0x5555, 0xAA55)
        self.const_floor_pattern_mode_2_words: tuple[int, ...] = (0x8181, 0x6681, 0x6666, 0x1866, 0x1818, 0x6618, 0x6666, 0x8166)
        self.const_floor_pattern_words_by_mode: tuple[tuple[int, ...], ...] = (
            self.const_floor_pattern_mode_0_words,
            self.const_floor_pattern_mode_1_words,
            self.const_floor_pattern_mode_2_words,
        )

        # ZX 0xA8B0..0xA8B1
        # Typed u16 prelude word for runtime-control bootstrap.
        self.var_runtime_control_prelude: int = 0x0000
        # ZX 0xA8B2..0xA8DA
        self.var_runtime_control_core = bytearray(0x0029)

        # ZX 0xA8DB..0xA8DD
        # +0x00 active_map_mode, +0x01 action_effect_flags, +0x02 strip_fill_value.
        self.var_active_map_mode: int = _DEFAULT_ACTIVE_MAP_MODE
        self.var_action_effect_flags: int = _DEFAULT_ACTION_EFFECT_FLAGS
        self.var_strip_fill_value: int = _DEFAULT_STRIP_FILL_VALUE

        # ZX 0xA8DE..0xA8DF
        # +0x00 col (C remainder), +0x01 row (B quotient) from 0xEBEB conversion.
        self.var_current_map_coords: MapCoords = MapCoords(
            col=_DEFAULT_CURRENT_MAP_COORDS.col,
            row=_DEFAULT_CURRENT_MAP_COORDS.row,
        )
        self.var_marker_event_cell_ptr: BlockPtr = BlockPtr(self.var_level_map_mode_0, 0x0000)

        # ZX 0xA8E2..0xA8E2
        # Marker animation/selection index byte.
        self.var_marker_index_state: int = 0x00

        # ZX 0xA8E3..0xA8E7
        # Five marker-state flags (u8 each), indexed by marker id 0..4.
        self.var_marker_counters: MarkerCounters = MarkerCounters()

        # ZX 0xA8E8..0xA8E8
        self.var_menu_selection_index: int = _DEFAULT_MENU_SELECTION_INDEX
        # ZX 0xA8E9..0xA8F1
        self.var_runtime_reserve_tail = bytearray(0x0009)
        # ZX 0xA8F2..0xAF71
        self.var_active_sprite_subset_bank = bytearray.fromhex("")
        # ZX 0xAF72..0xB733
        self.const_sprite_table_continuation = bytes.fromhex("")

        # ZX 0xB734..0xB8AF
        # Original layout: repeated [cell_value, cell_lo, cell_hi] with 0xFF sentinel.
        # Port stores semantic restore records as typed list entries.
        self.var_saved_map_triplet_buffer: list[MapRestoreEntry] = []

        # ZX 0xB8B0..0xB8B1
        # Typed u16 scratch tail used by sprite-bank setup paths.
        self.var_runtime_sprite_tail: int = 0x0000
        # ZX 0xB8B2..0xBF31
        self.const_sprite_subset_bank_a = bytearray.fromhex("")
        # ZX 0xBF32..0xC5B1
        self.const_sprite_subset_bank_b = bytearray.fromhex("")

        # ZX 0xC5B2..0xCD1D
        # Runtime object queues were [state,u16 cell_ptr] triplets.
        # Port stores semantic queue entries directly.
        self.var_runtime_object_queue_0: RuntimeObjectQueueBuffer = RuntimeObjectQueueBuffer(
            entries=[
                RuntimeObjectQueueEntry(state=0xFF, cell_ptr=None)
                for _ in range(_RUNTIME_OBJECT_QUEUE_ENTRY_COUNT)
            ],
        )
        self.var_runtime_object_queue_1: RuntimeObjectQueueBuffer = RuntimeObjectQueueBuffer(
            entries=[
                RuntimeObjectQueueEntry(state=0xFF, cell_ptr=None)
                for _ in range(_RUNTIME_OBJECT_QUEUE_ENTRY_COUNT)
            ],
        )
        self.var_runtime_object_queue_2: RuntimeObjectQueueBuffer = RuntimeObjectQueueBuffer(
            entries=[
                RuntimeObjectQueueEntry(state=0xFF, cell_ptr=None)
                for _ in range(_RUNTIME_OBJECT_QUEUE_ENTRY_COUNT)
            ],
        )
        self.var_runtime_object_queue_3: RuntimeObjectQueueBuffer = RuntimeObjectQueueBuffer(
            entries=[
                RuntimeObjectQueueEntry(state=0xFF, cell_ptr=None)
                for _ in range(_RUNTIME_OBJECT_QUEUE_ENTRY_COUNT)
            ],
        )
        self.var_runtime_object_queue_4: RuntimeObjectQueueBuffer = RuntimeObjectQueueBuffer(
            entries=[
                RuntimeObjectQueueEntry(state=0xFF, cell_ptr=None)
                for _ in range(_RUNTIME_OBJECT_QUEUE_ENTRY_COUNT)
            ],
        )
        # ZX 0xCD1E..0xD6E1
        self.var_level_map_mode_1 = bytearray.fromhex("")
        # ZX 0xD6E2..0xE0A5
        self.var_level_map_mode_2 = bytearray.fromhex("")

        # ZX 0xE0A6..0xE0A6
        self.const_patch_seed_gameplay_movement_step_opcode: int = (
            _DEFAULT_PATCH_SEED_GAMEPLAY_MOVEMENT_STEP_OPCODE
        )

        # ZX 0xE3AD..0xE3AD
        # Single-byte movement marker scratch register.
        self.var_move_marker_code_scratch: int = 0x00

